```class Solution {
    public int findIntegers(int n) {
        int res = 0, prev = 0, curr = 1;
        for (int i = 0; i <= n; i++) {
            if ((i & (i >> 1)) == 0) {
                res++;
                if (i == n) break;
                prev = curr;
                curr = i + 1;
            } else {
                curr = prev + 1;
            }
        }
        return res;
    }
}```
